Bash(powershell -Command "
\\$cities = Get-Content '/tmp/sa_cities.json' -Raw | ConvertFrom-Json
Write-Output \('Total cities: ' + \\$cities.Count\)
\\$regions = \\$cities | Group-Object region_id | Sort-Object { [int]\\$_.Name }
foreach \(\\$r in \\$regions\) {
    Write-Output \('Region ' + \\$r.Name + ': ' + \\$r.Count + ' cities'\)
}
" 2>&1)

